12.query:
fetch spans

| filter isNotNull(request_attribute.Load.Script.Name) and isNotNull(request_attribute.Load.Test.Name) and isNotNull(request_attribute.Test.Step.Name)
| fields start_time, duration, script_name=request_attribute.Load.Script.Name, test_name=request_attribute.Load.Test.Name, step_name=request_attribute.Test.Step.Name, vu=request_attribute.Test.Virtual.User, http.response.status_code
//Filter Param here
| filter in(test_name, $Test_Name) 
| filter in(script_name, $Script_Name) 
| filter in(step_name, $Step_Name)

//Summary
| summarize Throughput = count(), Avg_Response_Time = avg(duration), Active_Users=countDistinct(vu),
            by: {bin(start_time, 1m)}
//| sort timestamp asc
//| makeTimeseries Throughput=count(), respontime=avg(duration), interval:1m
